import json
import sys

def load_game_data(file_path):
    with open(file_path, 'r') as file:
        return json.load(file)

def display_room(room):
    print(room['description'])
    for i, choice in enumerate(room.get('choices', [])):
        print(f"{i + 1}. {choice['description']}")

def get_player_choice(num_choices):
    choice = 0
    while choice < 1 or choice > num_choices:
        try:
            choice = int(input("Choose an option: "))
            if choice < 1 or choice > num_choices:
                print(f"Please enter a number between 1 and {num_choices}.")
        except ValueError:
            print("Please enter a valid number.")
    return choice

def main(game_file):
    game_data = load_game_data(game_file)
    current_room = game_data['start']

    while True:
        room = game_data['rooms'][current_room]
        display_room(room)

        if 'choices' not in room or len(room['choices']) == 0:
            print("Game Over")
            break

        player_choice = get_player_choice(len(room['choices']))
        current_room = room['choices'][player_choice - 1]['next_room']

if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("Usage: python adventure_game.py <game_data_file>")
        sys.exit(1)
    game_file = sys.argv[1]
    main(game_file)

